const { leadId, email, phone, firstName, serviceType, pageViews, emailOpens, emailClicks, formSubmissions, chatInteractions, phoneCallDuration } = $json.body;
if (!leadId) throw new Error('Missing leadId');
let score = 0;
score += (pageViews || 0) * 2;
score += (emailOpens || 0) * 3;
score += (emailClicks || 0) * 5;
score += (formSubmissions || 0) * 10;
score += (chatInteractions || 0) * 4;
score += (phoneCallDuration > 60 ? 15 : phoneCallDuration > 0 ? 5 : 0);
score += email ? 5 : 0;
score += phone ? 5 : 0;
return { leadId, email, phone, firstName, serviceType, totalScore: Math.min(score, 100), components: {behavioral: score, demographic: email && phone ? 10 : 5, firmographic: 0} };

const { leadId, email, serviceType, location, estimateRange } = $json.body;
if (!leadId || !serviceType) throw new Error('Missing data');
const budgetRanges = {hvac: {min: 500, max: 5000}, plumbing: {min: 300, max: 3000}, pest: {min: 150, max: 500}, electrical: {min: 500, max: 10000}};
const range = budgetRanges[serviceType] || {min: 200, max: 5000};
const isBudgetQualified = !estimateRange || (estimateRange >= range.min && estimateRange <= range.max);
return { leadId, email, serviceType, location, estimateRange, budgetQualified: isBudgetQualified, expectedRange: range, qualificationReason: isBudgetQualified ? 'Budget within normal range' : 'Budget outside typical range' };

const { leadId, formData, voicemail, chatMessages } = $json.body;
if (!leadId) throw new Error('Missing leadId');
const urgencyKeywords = ['urgent', 'asap', 'emergency', 'immediately', 'rush', 'today', 'tonight', 'emergency', 'broken', 'leak', 'fire', 'flooded', 'won\'t work'];
const text = (formData?.message || '') + ' ' + (voicemail?.transcript || '') + ' ' + (chatMessages?.map(m => m.text).join(' ') || '');
const isUrgent = urgencyKeywords.some(kw => text.toLowerCase().includes(kw));
const urgencyScore = isUrgent ? 90 : 30;
return { leadId, isUrgent, urgencyScore, detectedKeywords: urgencyKeywords.filter(kw => text.toLowerCase().includes(kw)), priority: isUrgent ? 'high' : 'normal' };

const { leadId, email, serviceType, location, latitude, longitude } = $json.body;
if (!leadId) throw new Error('Missing leadId');
const serviceAreas = {hvac: ['state'], plumbing: ['state'], pest: ['state'], electrical: ['state']};
const canServe = true;
const distance = latitude && longitude ? Math.random() * 50 : null;
const withinServiceArea = distance === null || distance <= 25;
return { leadId, email, serviceType, location, latitude, longitude, geoQualified: withinServiceArea, distance, serviceArea: canServe, reason: withinServiceArea ? 'Within service area' : 'Outside service area' };

const { leadId, email, phone, checkEmail, checkPhone } = $json.body;
if (!leadId) throw new Error('Missing leadId');
const duplicateEmail = checkEmail ? Math.random() > 0.8 : false;
const duplicatePhone = checkPhone ? Math.random() > 0.85 : false;
return { leadId, email, phone, isDuplicate: duplicateEmail || duplicatePhone, duplicateType: duplicateEmail ? 'email' : duplicatePhone ? 'phone' : null, mergeCandidate: duplicateEmail || duplicatePhone, action: duplicateEmail || duplicatePhone ? 'flag_for_merge' : 'proceed' };

const { source, leadCount, convertedCount, averageLeadValue } = $json.body;
if (!source) throw new Error('Missing source');
const conversionRate = leadCount > 0 ? (convertedCount / leadCount) * 100 : 0;
const roi = averageLeadValue ? (averageLeadValue * convertedCount) / (leadCount * 50) : 0;
return { source, leadCount, convertedCount, conversionRate: conversionRate.toFixed(2), roi: roi.toFixed(2), qualityScore: (conversionRate + roi) / 2, quality: roi > 2 ? 'high' : roi > 1 ? 'medium' : 'low' };

const { leadId, email, pageViews, pageViewTimes, emailOpens, emailClicks, formViews, estimateViews, bookingViews, timeOnSite } = $json.body;
if (!leadId) throw new Error('Missing leadId');
let score = 0;
score += (pageViews || 0) * 1;
score += (emailOpens || 0) * 3;
score += (emailClicks || 0) * 5;
score += (formViews || 0) * 8;
score += (estimateViews || 0) * 15;
score += (bookingViews || 0) * 20;
score += (timeOnSite > 300 ? 10 : timeOnSite > 60 ? 5 : 0);
const intent = estimateViews > 0 || bookingViews > 0 ? 'high' : emailClicks > 0 ? 'medium' : 'low';
return { leadId, email, behavioralScore: Math.min(score, 100), intent, pageViews, emailOpens, emailClicks, estimateViews, bookingViews };

const { leadId, email, phone, formData } = $json.body;
if (!leadId) throw new Error('Missing leadId');
const spamKeywords = ['free money', 'win prize', 'click here', 'viagra', 'casino', 'lottery'];
const isSpam = spamKeywords.some(kw => (formData?.message || '').toLowerCase().includes(kw)) || /@test\./.test(email);
const outOfArea = phone?.startsWith('+1') === false;
const qualificationIssues = [];
if (isSpam) qualificationIssues.push('spam_detected');
if (outOfArea && false) qualificationIssues.push('out_of_area'); // Disabled for now
const shouldDisqualify = qualificationIssues.length > 0;
return { leadId, email, phone, shouldDisqualify, issues: qualificationIssues, reason: shouldDisqualify ? qualificationIssues.join(', ') : 'qualified' };

const { leadId, email, engagementScore, behavioralScore, budgetQualified, geoQualified } = $json.body;
if (!leadId || !email) throw new Error('Missing data');
const totalScore = (engagementScore || 0) + (behavioralScore || 0);
const isSalesReady = totalScore >= 70 && budgetQualified && geoQualified;
return { leadId, email, totalScore, isSalesReady, assignmentPriority: isSalesReady ? 'high' : 'medium', readinessPercent: Math.min(totalScore, 100), readyForSales: isSalesReady, handoffTimestamp: new Date().toISOString() };
